import{_ as a,o as n,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Facturen","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/invoices.md","filePath":"nl/features/invoices.md"}'),l={name:"nl/features/invoices.md"};function i(o,e,s,u,d,c){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="facturen" tabindex="-1">Facturen <a class="header-anchor" href="#facturen" aria-label="Permalink to &quot;Facturen&quot;">​</a></h1><p>Facturen vormen de kern van MyCompanyDesk. Maak professionele facturen, verstuur ze naar klanten met betaallinks en volg betalingen tot aan de afhandeling.</p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>De facturenpagina toont al je facturen met filter- en zoekmogelijkheden. Gebruik de statustabs om snel te bekijken:</p><ul><li><strong>Alles</strong> — Alle facturen</li><li><strong>Concept</strong> — Aangemaakt maar niet verstuurd</li><li><strong>Verzonden</strong> — Bezorgd bij klanten</li><li><strong>Achterstallig</strong> — Vervaldatum verstreken, onbetaald</li><li><strong>Betaald</strong> — Betaling ontvangen</li><li><strong>Geannuleerd</strong> — Geannuleerde facturen</li></ul><h2 id="een-factuur-aanmaken" tabindex="-1">Een factuur aanmaken <a class="header-anchor" href="#een-factuur-aanmaken" aria-label="Permalink to &quot;Een factuur aanmaken&quot;">​</a></h2><h3 id="volledig-formulier" tabindex="-1">Volledig formulier <a class="header-anchor" href="#volledig-formulier" aria-label="Permalink to &quot;Volledig formulier&quot;">​</a></h3><ol><li>Ga naar <strong>Facturen &gt; Nieuwe factuur</strong></li><li>Selecteer of maak een <strong>klant</strong> aan</li><li>Voeg <strong>regelitems</strong> toe met omschrijving, aantal, eenheidsprijs en BTW-tarief</li><li>Stel de <strong>factuurdatum</strong> en <strong>vervaldatum</strong> in</li><li>Voeg optionele <strong>notities</strong> of <strong>interne opmerkingen</strong> toe</li><li>Klik op <strong>Opslaan</strong> om een concept aan te maken</li></ol><h3 id="snel-toevoegen" tabindex="-1">Snel toevoegen <a class="header-anchor" href="#snel-toevoegen" aria-label="Permalink to &quot;Snel toevoegen&quot;">​</a></h3><p>Voor snellere aanmaak:</p><ol><li>Klik op de snel-toevoegen-knop op de facturenlijst</li><li>Selecteer een klant</li><li>Voeg items toe of kies een sjabloon</li><li>Sla op (en verstuur optioneel direct)</li></ol><h3 id="vanuit-een-sjabloon" tabindex="-1">Vanuit een sjabloon <a class="header-anchor" href="#vanuit-een-sjabloon" aria-label="Permalink to &quot;Vanuit een sjabloon&quot;">​</a></h3><ol><li>Klik bij het aanmaken van een nieuwe factuur op <strong>Sjabloon gebruiken</strong></li><li>Selecteer een opgeslagen sjabloon</li><li>Alle regelitems zijn vooraf ingevuld — pas aan waar nodig</li><li>Sla op en verstuur</li></ol><h2 id="factuurdetails" tabindex="-1">Factuurdetails <a class="header-anchor" href="#factuurdetails" aria-label="Permalink to &quot;Factuurdetails&quot;">​</a></h2><p>Elke factuur heeft een detailpagina met:</p><ul><li>Klantinformatie</li><li>Regelitems met subtotalen</li><li>BTW-specificatie</li><li>Totaalbedrag</li><li>Status en geschiedenis</li><li>Betaallink (indien verstuurd)</li></ul><h2 id="acties" tabindex="-1">Acties <a class="header-anchor" href="#acties" aria-label="Permalink to &quot;Acties&quot;">​</a></h2><h3 id="versturen" tabindex="-1">Versturen <a class="header-anchor" href="#versturen" aria-label="Permalink to &quot;Versturen&quot;">​</a></h3><p>Verstuur de factuur per e-mail naar je klant. De e-mail bevat:</p><ul><li>Een aanpasbaar bericht (gebaseerd op je e-mailsjabloon)</li><li>De factuur-PDF als bijlage</li><li>Een betaallink voor online betaling</li></ul><h3 id="pdf-downloaden" tabindex="-1">PDF downloaden <a class="header-anchor" href="#pdf-downloaden" aria-label="Permalink to &quot;PDF downloaden&quot;">​</a></h3><p>Download de factuur als een professioneel opgemaakt PDF-document. De PDF bevat je bedrijfslogo, huisstijlkleuren en alle factuurgegevens.</p><h3 id="markeer-als-betaald" tabindex="-1">Markeer als betaald <a class="header-anchor" href="#markeer-als-betaald" aria-label="Permalink to &quot;Markeer als betaald&quot;">​</a></h3><p>Bevestig handmatig de betaling wanneer een klant per bankoverschrijving of andere offline methode betaalt.</p><h3 id="annuleren" tabindex="-1">Annuleren <a class="header-anchor" href="#annuleren" aria-label="Permalink to &quot;Annuleren&quot;">​</a></h3><p>Annuleer een factuur die niet meer betaald hoeft te worden. Geannuleerde facturen blijven in je administratie voor controledoeleinden.</p><h3 id="dupliceren" tabindex="-1">Dupliceren <a class="header-anchor" href="#dupliceren" aria-label="Permalink to &quot;Dupliceren&quot;">​</a></h3><p>Maak een kopie van een bestaande factuur — handig voor terugkerende facturatie aan dezelfde klant.</p><h3 id="herinnering-sturen" tabindex="-1">Herinnering sturen <a class="header-anchor" href="#herinnering-sturen" aria-label="Permalink to &quot;Herinnering sturen&quot;">​</a></h3><p>Verstuur een betalingsherinnering voor achterstallige facturen.</p><h2 id="bulkacties" tabindex="-1">Bulkacties <a class="header-anchor" href="#bulkacties" aria-label="Permalink to &quot;Bulkacties&quot;">​</a></h2><p>Selecteer meerdere facturen uit de lijst om acties in bulk uit te voeren:</p><ul><li><strong>Versturen</strong> — Verstuur meerdere conceptfacturen tegelijk</li><li><strong>Markeer als betaald</strong> — Registreer betalingen voor meerdere facturen</li><li><strong>Archiveren</strong> — Verplaats facturen naar het archief</li><li><strong>Verwijderen</strong> — Verwijder facturen permanent</li></ul><h2 id="betaallinks" tabindex="-1">Betaallinks <a class="header-anchor" href="#betaallinks" aria-label="Permalink to &quot;Betaallinks&quot;">​</a></h2><p>Wanneer je een factuur verstuurt, wordt een unieke betaallink gegenereerd. Je klant kan:</p><ol><li>Op de link in de e-mail klikken</li><li>De factuur bekijken in het <strong>klantportaal</strong></li><li>Direct online betalen</li></ol><p>De betaling wordt automatisch geregistreerd en de factuurstatus wordt bijgewerkt naar <strong>Betaald</strong>.</p><h2 id="documenttypen" tabindex="-1">Documenttypen <a class="header-anchor" href="#documenttypen" aria-label="Permalink to &quot;Documenttypen&quot;">​</a></h2><p>De factuurmodule ondersteunt meerdere documenttypen:</p><ul><li><strong>Factuur</strong> — Standaard factuurtype</li><li><strong>Creditnota</strong> — Correctie voor terugbetalingen of aanpassingen</li><li><strong>Herinnering</strong> — Betalingsherinnering voor achterstallige facturen</li></ul><h2 id="filteren-en-zoeken" tabindex="-1">Filteren en zoeken <a class="header-anchor" href="#filteren-en-zoeken" aria-label="Permalink to &quot;Filteren en zoeken&quot;">​</a></h2><p>Gebruik de filterbalk om je facturen te verfijnen:</p><ul><li><strong>Status</strong> — Concept, Verzonden, Achterstallig, Betaald, Geannuleerd</li><li><strong>Klant</strong> — Filter op specifieke klant</li><li><strong>Project</strong> — Filter op gekoppeld project</li><li><strong>Datumbereik</strong> — Filter op factuur- of vervaldatum</li><li><strong>Zoeken</strong> — Zoek op factuurnummer, klantnaam of omschrijving</li></ul><h2 id="exporteren" tabindex="-1">Exporteren <a class="header-anchor" href="#exporteren" aria-label="Permalink to &quot;Exporteren&quot;">​</a></h2><p>Exporteer je facturen als CSV voor gebruik in Excel, Google Sheets of je boekhoudsoftware.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>CSV-export vereist het <strong>Pro</strong>-abonnement of hoger.</p></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Stel je <a href="/nl/settings/email">e-mailsjablonen</a> in voordat je je eerste factuur verstuurt</li><li>Gebruik <a href="/nl/features/recurring-invoices">terugkerende facturen</a> voor regelmatige facturatie</li><li>Bekijk de <a href="/nl/features/reports">rapportages</a> pagina voor omzetinzichten</li><li>Schakel <a href="/nl/advanced/ai-features">AI-suggesties</a> in voor slimme omschrijvingsverbeteringen</li></ul>',48)])])}const f=a(l,[["render",i]]);export{h as __pageData,f as default};
